  window.openPayrollForEmployee18=id=>{state.payrollEmployeeFilter=id;state.payrollRangeMode='employment';setRangeMode18('employment',false);$('#drawerOverlay').classList.remove('show');setPage('payroll')};

  function currentRange18(){return {from:state.payrollDateFrom,to:state.payrollDateTo}}
  function earliestPayrollDate18(employeeId=''){const employee=state.employees.find(x=>x.id===employeeId),dates=[employee?.start_date,...state.employees.map(x=>x.start_date),...state.attendanceEvents.map(x=>x.event_date),...state.payrollAdjustments.map(x=>x.adjustment_date),...state.timesheets.map(x=>x.work_date)].filter(Boolean).sort();return dates[0]||monthStart18(state.payrollYear,state.payrollMonth)}
  function setRangeMode18(mode,draw=true){state.payrollRangeMode=mode;const end=monthEnd18(state.payrollYear,state.payrollMonth);if(mode==='month'){state.payrollDateFrom=monthStart18(state.payrollYear,state.payrollMonth);state.payrollDateTo=end}else if(mode==='three'){const d=new Date(Number(state.payrollYear),Number(state.payrollMonth)-3,1);state.payrollDateFrom=iso18(d);state.payrollDateTo=end}else if(mode==='all'){state.payrollDateFrom=earliestPayrollDate18();state.payrollDateTo=today18()}else if(mode==='employment'){state.payrollDateFrom=earliestPayrollDate18(state.payrollEmployeeFilter);state.payrollDateTo=today18()}if(draw)renderPage()}
  window.setPayrollRangeMode18=v=>setRangeMode18(v);
  window.setPayrollFrom18=v=>{state.payrollDateFrom=v;state.payrollRangeMode='custom';renderPage()};
  window.setPayrollTo18=v=>{state.payrollDateTo=v;state.payrollRangeMode='custom';renderPage()};
