  function workers18(){const rows=payrollEmployees18().map(e=>{const r=rateInfo18(e),t=tenure18(e.start_date,e.end_date);return [`<div class="entity"><div class="employee-photo">${esc(initials18(e.full_name))}</div><div><b>${esc(e.full_name)}</b><small>${esc(e.job_title||'—')} · ${esc(e.department||'—')}</small></div></div>`,esc(paymentLabel18(e.payment_type)),format18(r.monthly),format18(r.daily),format18(r.hourly),format18(r.overtime),format18(r.project),format18(r.contract),`${t.days} / ${t.months} / ${t.years}`,`<button class="btn" onclick="editRecord('employee','${e.id}')">Edit</button>`]});return `<section class="panel payroll-hq-panel"><div class="panel-head"><div><h2>Сотрудники и ставки</h2><p>Дни / месяцы / годы стажа и все типы оплаты</p></div><button class="btn primary" onclick="openEmployeeModal()">＋ Сотрудник</button></div>${table18(['EMPLOYEE','TYPE','MONTHLY','DAILY','HOURLY','OVERTIME','PROJECT','CONTRACT','TENURE D/M/Y',''],rows)}</section>`}
  function journal18(){const from=state.payrollDateFrom,to=state.payrollDateTo,events=state.attendanceEvents.filter(x=>inRange18(x.event_date,from,to)&&(!state.payrollEmployeeFilter||x.employee_id===state.payrollEmployeeFilter)),work=state.timesheets.filter(x=>inRange18(x.work_date,from,to)&&(!state.payrollEmployeeFilter||x.employee_id===state.payrollEmployeeFilter)),rows=[...events.map(x=>({d:x.event_date,e:x.employee_id,p:x.project_id,type:x.event_type,qty:x.quantity,amount:x.amount,notes:x.notes,id:x.id,event:true})),...work.map(x=>({d:x.work_date,e:x.employee_id,p:x.project_id,type:'work',qty:x.regular_hours,amount:0,notes:x.notes,id:x.id}))].sort((a,b)=>String(b.d).localeCompare(String(a.d)));return `<section class="panel payroll-hq-panel"><div class="panel-head"><div><h2>Журнал</h2><p>Work hours, Absence, Overtime and Advance — transaction rows by date</p></div><div class="payroll-secondary-actions"><button class="btn" onclick="openWorkHours18()">＋ Work hours</button><button class="btn primary" onclick="openAttendanceEvent18()">＋ Exception / advance</button></div></div>${table18(['DATE','EMPLOYEE','PROJECT','TYPE','QTY / HOURS','AMOUNT','NOTE',''],rows.map(x=>[date(x.d),esc(labelEmployee18(x.e)),esc(labelProject18(x.p)),`<span class="${x.type==='absence'?'payroll-num-absence':x.type==='overtime'?'payroll-num-overtime':x.type==='advance'?'payroll-num-advance':''}">${esc(x.type)}</span>`,n18(x.qty),x.type==='absence'?`<span class="payroll-num-absence">${format18(Math.abs(n18(x.amount)))}</span>`:x.type==='overtime'||x.type==='advance'?`<span class="payroll-num-overtime">${format18(x.amount)}</span>`:'0',esc(x.notes||'—'),x.event?`<button class="btn" onclick="openAttendanceEvent18('${x.id}')">Edit</button>`:`<button class="btn" onclick="openWorkHours18('${x.id}')">Edit</button>`]))}</section>`}
