  function year18(){const months=Array.from({length:12},(_,i)=>i+1),employees=state.employees.filter(e=>!state.payrollEmployeeFilter||e.id===state.payrollEmployeeFilter);return `<section class="panel payroll-hq-panel"><div class="salary-sheet-head"><h2>SPACE BURO — ГОДОВАЯ СВОДКА ${state.payrollYear}</h2><p>Balance по каждому сотруднику; даты начисления учитывают Start date</p></div>${table18(['EMPLOYEE',...months.map(m=>new Intl.DateTimeFormat('ru',{month:'short'}).format(new Date(2026,m-1,1)).toUpperCase()),'TOTAL'],employees.map(e=>{const values=months.map(m=>employeeCalc18(e,monthStart18(state.payrollYear,m),monthEnd18(state.payrollYear,m)).balance);return [`<b>${esc(e.full_name)}</b>`,...values.map(x=>format18(x)),`<b>${format18(sum18(values,x=>x))}</b>`]}),'year-summary')}</section>`}

