  window.sendDesignPayroll18=async id=>{const c=state.designCompensations.find(x=>x.id===id);if(!c.designer_id)throw new Error('Assign a designer first');if(c.payroll_adjustment_id)return;const day=c.payment_date||c.actual_finish_date||today18(),a=await insert('payroll_adjustments',{employee_id:c.designer_id,project_id:c.project_id||null,adjustment_date:day,period_year:new Date(day+'T00:00:00').getFullYear(),period_month:new Date(day+'T00:00:00').getMonth()+1,adjustment_type:'project_payment',amount:n18(c.final_payment),source_type:'design_compensation',source_id:c.id,approval_status:'approved',approved_at:new Date().toISOString(),approved_by:state.profile?.id,notes:`Design · ${c.project_number||c.room_type||id}`});await update('design_compensations',id,{payroll_adjustment_id:a.id,approval_status:'approved'});await loadAll();openDesignDrawer18(id);toast('Начисление дизайнера добавлено в общую зарплату')};
  window.recordDesignPayment18=id=>{const c=state.designCompensations.find(x=>x.id===id);openModal('Design payment',input('amount','Paid amount · AED','number',Math.max(0,n18(c.final_payment)-n18(c.paid_amount)),'min="0" step="0.01" required')+input('payment_date','Date','date',today18())+select('payment_method','Method','<option value="cash">Cash</option><option value="bank_transfer">Bank Transfer</option><option value="card">Card</option><option value="other">Other</option>')+input('reference','Reference')+`<label class="full">Comment<textarea name="notes"></textarea></label>`,async d=>{if(!c.designer_id)throw new Error('Assign a designer first');const day=d.payment_date,amount=n18(d.amount);await insert('payroll_adjustments',{employee_id:c.designer_id,project_id:c.project_id||null,adjustment_date:day,period_year:new Date(day+'T00:00:00').getFullYear(),period_month:new Date(day+'T00:00:00').getMonth()+1,adjustment_type:'salary_payment',amount,source_type:'design_compensation',source_id:c.id,payment_method:d.payment_method,approval_status:'approved',approved_at:new Date().toISOString(),approved_by:state.profile?.id,notes:d.notes||`Design payment · ${d.reference||c.project_number||id}`});return update('design_compensations',id,{paid_amount:n18(c.paid_amount)+amount,payment_date:day,payment_method:d.payment_method,approval_status:n18(c.paid_amount)+amount>=n18(c.final_payment)?'paid':c.approval_status})})};

  window.openContractorOperation18=(contractorId='',id='')=>{const x=id?state.contractorOperations.find(o=>o.id===id):{},c=state.contractors.find(v=>v.id===(x.contractor_id||contractorId));openModal(id?'Изменить операцию контрактора':'Операция контрактора',select('contractor_id','Contractor',`<option value="">Select contractor</option>${optionRows18(state.contractors,'id','full_name',x.contractor_id||contractorId)}`)+select('project_id','Project',`<option value="">Without project</option>${optionRows18(state.projects,'id','name',x.project_id||'')}`)+select('task_id','Task',`<option value="">Without task</option>${optionRows18(state.tasks,'id','title',x.task_id||'')}`)+input('description','Operation / work','text',x.description||'','required')+select('operation_type','Operation type',`<option value="project_work" ${x.operation_type==='project_work'?'selected':''}>Project work</option><option value="design" ${x.operation_type==='design'?'selected':''}>Design / drawings</option><option value="installation" ${x.operation_type==='installation'?'selected':''}>Installation</option><option value="consulting" ${x.operation_type==='consulting'?'selected':''}>Consulting</option><option value="milestone" ${x.operation_type==='milestone'?'selected':''}>Milestone</option><option value="other" ${x.operation_type==='other'?'selected':''}>Other</option>`)+select('pricing_type','Pricing',`<option value="variable" ${x.pricing_type==='variable'?'selected':''}>Variable / manual</option><option value="fixed" ${x.pricing_type==='fixed'?'selected':''}>Fixed</option><option value="unit" ${x.pricing_type==='unit'?'selected':''}>Per unit</option><option value="daily" ${x.pricing_type==='daily'?'selected':''}>Daily</option><option value="hourly" ${x.pricing_type==='hourly'?'selected':''}>Hourly</option><option value="percentage" ${x.pricing_type==='percentage'?'selected':''}>Percentage</option><option value="milestone" ${x.pricing_type==='milestone'?'selected':''}>Milestone</option>`)+input('quantity','Quantity','number',x.quantity||1,'min="0" step="0.001"')+input('unit','Unit','text',x.unit||'job')+input('rate','Rate · AED','number',x.rate||c?.default_rate||0,'min="0" step="0.01"')+input('base_amount','Base for percentage · AED','number',x.base_amount||0,'min="0" step="0.01"')+input('percentage','Percentage · %','number',x.percentage||0,'min="0" step="0.01"')+input('amount','Manual / fixed amount · AED','number',x.amount||0,'min="0" step="0.01"')+input('operation_date','Operation date','date',x.operation_date||today18())+input('due_date','Due date','date',x.due_date||'')+select('status','Status',`<option value="draft" ${x.status==='draft'?'selected':''}>Draft</option><option value="pending" ${x.status==='pending'?'selected':''}>Pending approval</option><option value="approved" ${x.status==='approved'?'selected':''}>Approved</option><option value="partially_paid" ${x.status==='partially_paid'?'selected':''}>Partially paid</option><option value="paid" ${x.status==='paid'?'selected':''}>Paid</option><option value="cancelled" ${x.status==='cancelled'?'selected':''}>Cancelled</option>`)+`<label class="full">Notes<textarea name="notes">${esc(x.notes||'')}</textarea></label>`,async d=>{if(!d.contractor_id)throw new Error('Выберите контрактора');const rec={contractor_id:d.contractor_id,project_id:d.project_id||null,task_id:d.task_id||null,description:d.description,operation_type:d.operation_type,pricing_type:d.pricing_type,quantity:n18(d.quantity),unit:d.unit||'job',rate:n18(d.rate),base_amount:n18(d.base_amount),percentage:n18(d.percentage),amount:n18(d.amount),operation_date:d.operation_date,due_date:d.due_date||null,status:d.status,notes:d.notes||null};return id?update('contractor_operations',id,rec):insert('contractor_operations',rec)})};
  window.openContractorPayment18=(contractorId='',operationId='')=>{const op=state.contractorOperations.find(x=>x.id===operationId),selected=contractorId||op?.contractor_id||'',ops=state.contractorOperations.filter(x=>!selected||x.contractor_id===selected);openModal('Выплата контрактору',select('contractor_id','Contractor',`<option value="">Select contractor</option>${optionRows18(state.contractors,'id','full_name',selected)}`)+select('operation_id','Operation',`<option value="">General payment</option>${ops.map(x=>`<option value="${x.id}" ${x.id===operationId?'selected':''}>${esc(x.description)} · balance ${format18(x.balance)} AED</option>`).join('')}`)+select('project_id','Project',`<option value="">Without project</option>${optionRows18(state.projects,'id','name',op?.project_id||'')}`)+input('amount','Amount · AED','number',op?Math.max(0,n18(op.balance)):0,'required min="0.01" step="0.01"')+input('payment_date','Payment date','date',today18())+select('payment_method','Method','<option value="cash">Cash</option><option value="bank_transfer">Bank Transfer</option><option value="card">Card</option><option value="cheque">Cheque</option><option value="other">Other</option>')+input('reference','Reference')+select('status','Status','<option value="paid">Paid</option><option value="draft">Draft</option><option value="cancelled">Cancelled</option>')+`<label class="full">Notes<textarea name="notes"></textarea></label>`,async d=>{if(!d.contractor_id)throw new Error('Выберите контрактора');return insert('contractor_payments',{contractor_id:d.contractor_id,operation_id:d.operation_id||null,project_id:d.project_id||null,amount:n18(d.amount),payment_date:d.payment_date,payment_method:d.payment_method,reference:d.reference||null,status:d.status,notes:d.notes||null})});setTimeout(()=>{const f=$('#modalForm');if(!f)return;f.elements.contractor_id.onchange=()=>{const id=f.elements.contractor_id.value,rows=state.contractorOperations.filter(x=>x.contractor_id===id);f.elements.operation_id.innerHTML='<option value="">General payment</option>'+rows.map(x=>`<option value="${x.id}">${esc(x.description)} · ${format18(x.balance)} AED</option>`).join('')}},0)};
  function contractors18(){const ops=state.contractorOperations.filter(x=>inRange18(x.operation_date,state.payrollDateFrom,state.payrollDateTo)),payments=state.contractorPayments.filter(x=>inRange18(x.payment_date,state.payrollDateFrom,state.payrollDateTo)),accrued=sum18(ops,x=>n18(x.approved_amount)||n18(x.amount)),paid=sum18(payments.filter(x=>x.status==='paid'),'amount'),balance=accrued-paid;return `<div class="contractor-summary-grid">${kpi('▣','Контракторов',state.contractors.filter(x=>x.status==='active').length,'active')}${kpi('AED','Начислено',format18(accrued),'AED')}${kpi('✓','Выплачено',format18(paid),'AED')}${kpi('◷','Остаток',format18(balance),'AED')}</div><section class="panel payroll-hq-panel"><div class="panel-head other-payments-head"><div><h2>Операции контракторов</h2><p>Fixed, variable, unit, daily, hourly, percentage and milestone payments</p></div><div class="payroll-secondary-actions"><button class="btn" onclick="openContractorModal18()">＋ Контрактор</button><button class="btn primary" onclick="openContractorOperation18()">＋ Операция</button></div></div>${table18(['DATE','CONTRACTOR','PROJECT / TASK','DESCRIPTION','PRICING','QTY × RATE / %','ACCRUED','PAID','BALANCE','STATUS',''],ops.map(x=>[date(x.operation_date),`<button class="btn" onclick="openContractor18('${x.contractor_id}')">${esc(labelContractor18(x.contractor_id))}</button>`,`${esc(labelProject18(x.project_id))}<br><small>${esc(state.tasks.find(t=>t.id===x.task_id)?.title||'—')}</small>`,esc(x.description),esc(x.pricing_type),`${n18(x.quantity)} × ${format18(x.rate)} / ${n18(x.percentage)}%`,format18(n18(x.approved_amount)||n18(x.amount)),format18(x.paid_amount),`<b>${format18(x.balance)}</b>`,esc(x.status),`<button class="btn" onclick="openContractorOperation18('','${x.id}')">Edit</button> <button class="btn primary" onclick="openContractorPayment18('${x.contractor_id}','${x.id}')">Pay</button>`]))}</section><section class="panel payroll-hq-panel"><div class="panel-head other-payments-head"><div><h2>Журнал выплат контракторам</h2><p>Каждая выплата связана с человеком, проектом и при необходимости операцией</p></div><button class="btn primary" onclick="openContractorPayment18()">＋ Выплата</button></div>${table18(['DATE','CONTRACTOR','PROJECT','OPERATION','METHOD','REFERENCE','STATUS','AMOUNT'],payments.map(x=>[date(x.payment_date),esc(labelContractor18(x.contractor_id)),esc(labelProject18(x.project_id)),esc(state.contractorOperations.find(o=>o.id===x.operation_id)?.description||'General'),esc(x.payment_method||'—'),esc(x.reference||'—'),esc(x.status),`<b>${format18(x.amount)} AED</b>`]))}</section>`}

  payrollPage=function(){const body={workers:workers18,journal:journal18,summary:summary18,year:year18,calendar:calendar18,other:otherPayments18,contractors:contractors18}[state.payrollTab]||summary18;return payrollToolbar18()+`<div class="section-gap">${body()}</div>`};

  renderPage=function(){if(state.page==='employees'){baseRender18();$('#content').innerHTML=employeesPage()}else if(state.page==='payroll'){baseRender18();$('#content').innerHTML=payrollPage()}else baseRender18();relabel18()};
